import {
  ChangeDetectorRef,
  Component,
  ElementRef,
  Input as InputDecorator,
  NgZone,
  booleanAttribute,
  inject,
} from '@angular/core';
import { ProxyInputs } from '@ui5/webcomponents-ngx/utils';
import '@ui5/webcomponents/dist/TableRow.js';
import TableRow from '@ui5/webcomponents/dist/TableRow.js';
@ProxyInputs(['rowKey', 'interactive', 'navigated'])
@Component({
  standalone: true,
  selector: 'ui5-table-row',
  template: '<ng-content></ng-content>',
  inputs: ['rowKey', 'interactive', 'navigated'],
  exportAs: 'ui5TableRow',
})
class TableRowComponent {
  /**
        Unique identifier of the row.
        */
  rowKey!: string;
  /**
        Defines the interactive state of the row.
        */
  @InputDecorator({ transform: booleanAttribute })
  interactive!: boolean;
  /**
        Defines the navigated state of the row.
        */
  @InputDecorator({ transform: booleanAttribute })
  navigated!: boolean;

  private elementRef: ElementRef<TableRow> = inject(ElementRef);
  private zone = inject(NgZone);
  private cdr = inject(ChangeDetectorRef);

  get element(): TableRow {
    return this.elementRef.nativeElement;
  }

  constructor() {
    this.cdr.detach();
  }
}
export { TableRowComponent };
